PHP_STENCIL_CDEFS_EOT;

    /// Call this once, before touching any generated class, with the path to the
    /// compiled `nucleation` shared library (.so/.dylib/.dll). Falls back to the
    /// NUCLEATION_LIBRARY_PATH environment variable if never called explicitly.
    public static function init(string $libraryPath): void {
        if (self::$ffi !== null) {
            throw new \RuntimeException('Stencil\\Lib::init() called after the library was already loaded');
        }
        self::$libraryPath = $libraryPath;
    }

    public static function ffi(): \FFI {
        if (self::$ffi === null) {
            $path = self::$libraryPath ?? getenv('NUCLEATION_LIBRARY_PATH');
            if ($path === false || $path === null) {
                throw new \RuntimeException(
                    'Stencil\\Lib: no library path set — call Lib::init($path) or set the NUCLEATION_LIBRARY_PATH environment variable'
                );
            }
            self::$ffi = \FFI::cdef(self::CDEFS, $path);
        }
        return self::$ffi;
    }

    public static function readAndFreeWrite(\FFI\CData $write): string {
        $ffi = self::ffi();
        $len = $ffi->diplomat_buffer_write_len($write);
        $bytes = $ffi->diplomat_buffer_write_get_bytes($write);
        $str = \FFI::string($bytes, $len);
        $ffi->diplomat_buffer_write_destroy($write);
        return $str;
    }
}
